const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// Brewline — database schema\n//\n// One canonical model per domain entity; the client- and server-\n// side stores are thin caches on top of these tables. See\n// `prisma/seed.ts` for representative data.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\n// Connection URL lives in `prisma.config.ts` (Prisma 7 requirement);\n// runtime clients pass an adapter — see `src/lib/prisma.ts`.\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ──────────────────────────────────────────────────────────────\n// Identity & access\n// ──────────────────────────────────────────────────────────────\n\nenum Role {\n  admin\n  manager\n  cashier\n  kitchen\n}\n\nmodel User {\n  id           String       @id @default(cuid())\n  name         String\n  email        String       @unique\n  passwordHash String\n  role         Role\n  avatar       String?\n  createdAt    DateTime     @default(now())\n  updatedAt    DateTime     @updatedAt\n  sessions     Session[]\n  orders       Order[]\n  shifts       Shift[]\n  attendance   Attendance[]\n}\n\nmodel Session {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n}\n\n/// A team member added before being granted access. The Staff page\n/// creates these (name + email only). Settings → Team turns one into\n/// a real `User` by attaching a role + password; the draft is then\n/// deleted in the same transaction.\nmodel PendingMember {\n  id        String   @id @default(cuid())\n  name      String\n  email     String   @unique\n  createdAt DateTime @default(now())\n}\n\n// ──────────────────────────────────────────────────────────────\n// Payment channels (cashbook accounts)\n// ──────────────────────────────────────────────────────────────\n\n/// A configurable money channel — Cash drawer, wallet (EasyPaisa,\n/// JazzCash), or bank account. Each one tracks an opening balance\n/// and a running current balance; the current is mutated atomically\n/// by transfers (and, in a future iteration, by sales and supplier\n/// payouts).\n///\n/// Named `PaymentChannel` at the DB layer to keep the `PaymentMethod`\n/// enum (Order.payment) unambiguous — the UI still calls these\n/// \"Payment Methods\" since that's the operator's mental model.\nmodel PaymentChannel {\n  id             String            @id @default(cuid())\n  name           String            @unique\n  openingBalance Decimal           @db.Decimal(14, 2)\n  currentBalance Decimal           @db.Decimal(14, 2)\n  archived       Boolean           @default(false)\n  archivedAt     DateTime?\n  createdAt      DateTime          @default(now())\n  updatedAt      DateTime          @updatedAt\n  outgoing       PaymentTransfer[] @relation(\"transferFrom\")\n  incoming       PaymentTransfer[] @relation(\"transferTo\")\n}\n\n/// A money movement from one channel to another. The\n/// `createTransferAction` server action wraps `from -= amount`,\n/// `to += amount`, and this row in a single transaction so balances\n/// can never drift.\nmodel PaymentTransfer {\n  id         String         @id @default(cuid())\n  fromId     String\n  from       PaymentChannel @relation(\"transferFrom\", fields: [fromId], references: [id])\n  toId       String\n  to         PaymentChannel @relation(\"transferTo\", fields: [toId], references: [id])\n  amount     Decimal        @db.Decimal(14, 2)\n  occurredAt DateTime\n  note       String?\n  createdAt  DateTime       @default(now())\n\n  @@index([occurredAt])\n  @@index([fromId])\n  @@index([toId])\n}\n\n// ──────────────────────────────────────────────────────────────\n// Menu & kitchen routing\n// ──────────────────────────────────────────────────────────────\n\nmodel KitchenStation {\n  id        String          @id @default(cuid())\n  name      String          @unique\n  printer   String?\n  active    Boolean         @default(true)\n  color     String          @default(\"#6F4E37\")\n  menuItems MenuItem[]\n  tickets   KitchenTicket[]\n  createdAt DateTime        @default(now())\n  updatedAt DateTime        @updatedAt\n}\n\nmodel MenuCategory {\n  id        String     @id @default(cuid())\n  name      String\n  slug      String     @unique\n  color     String\n  items     MenuItem[]\n  createdAt DateTime   @default(now())\n}\n\nmodel MenuItem {\n  id              String             @id @default(cuid())\n  name            String\n  description     String?\n  price           Decimal            @db.Decimal(10, 2)\n  sku             String?            @unique\n  /// Pakistan Customs Tariff code reported per line item to BRA.\n  /// Falls back to FiscalConfig.defaultPctCode at submission time.\n  pctCode         String?\n  available       Boolean            @default(true)\n  posVisible      Boolean            @default(true)\n  popular         Boolean            @default(false)\n  prepTimeMinutes Int?\n  image           String?\n  categoryId      String\n  category        MenuCategory       @relation(fields: [categoryId], references: [id])\n  stationId       String\n  station         KitchenStation     @relation(fields: [stationId], references: [id])\n  modifiers       Json?\n  recipe          RecipeIngredient[]\n  orderItems      OrderItem[]\n  createdAt       DateTime           @default(now())\n  updatedAt       DateTime           @updatedAt\n\n  @@index([categoryId])\n  @@index([stationId])\n}\n\n// ──────────────────────────────────────────────────────────────\n// Inventory (raw materials)\n// ──────────────────────────────────────────────────────────────\n\nmodel Supplier {\n  id             String          @id @default(cuid())\n  name           String\n  contact        String?\n  email          String?\n  phone          String?\n  rating         Float           @default(0)\n  inventoryItems InventoryItem[]\n  createdAt      DateTime        @default(now())\n}\n\nmodel InventoryItem {\n  id            String              @id @default(cuid())\n  name          String\n  sku           String              @unique\n  category      String\n  unit          String\n  stock         Decimal             @db.Decimal(12, 3)\n  reorderLevel  Decimal             @db.Decimal(12, 3)\n  costPerUnit   Decimal             @db.Decimal(10, 4)\n  supplierId    String?\n  supplier      Supplier?           @relation(fields: [supplierId], references: [id])\n  lastRestocked DateTime?\n  expiresAt     DateTime?\n  recipes       RecipeIngredient[]\n  movements     InventoryMovement[]\n  createdAt     DateTime            @default(now())\n  updatedAt     DateTime            @updatedAt\n}\n\nmodel RecipeIngredient {\n  id              String        @id @default(cuid())\n  menuItemId      String\n  menuItem        MenuItem      @relation(fields: [menuItemId], references: [id], onDelete: Cascade)\n  inventoryItemId String\n  inventoryItem   InventoryItem @relation(fields: [inventoryItemId], references: [id])\n  quantity        Decimal       @db.Decimal(10, 4)\n  unit            String\n\n  @@unique([menuItemId, inventoryItemId])\n}\n\nmodel InventoryMovement {\n  id              String        @id @default(cuid())\n  inventoryItemId String\n  inventoryItem   InventoryItem @relation(fields: [inventoryItemId], references: [id], onDelete: Cascade)\n  delta           Decimal       @db.Decimal(12, 3) // negative for consumption, positive for restock\n  reason          String\n  orderId         String?\n  createdAt       DateTime      @default(now())\n\n  @@index([inventoryItemId])\n  @@index([orderId])\n}\n\n// ──────────────────────────────────────────────────────────────\n// Tables, orders, kitchen tickets\n// ──────────────────────────────────────────────────────────────\n\nmodel Table {\n  id        String   @id @default(cuid())\n  name      String   @unique\n  capacity  Int\n  occupancy Int      @default(0)\n  orders    Order[]\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum OrderStatus {\n  pending\n  preparing\n  ready\n  completed\n  cancelled\n  refunded\n}\n\nenum PaymentMethod {\n  card\n  cash\n  wallet\n  online\n}\n\nmodel Order {\n  id                  String             @id @default(cuid())\n  number              String             @unique\n  status              OrderStatus\n  /// Free-text channel (\"dine-in\" / \"takeaway\" / \"delivery\" / \"online\").\n  /// Kept as a string because \"dine-in\" can't appear in a Postgres enum.\n  channel             String\n  customerName        String?\n  customerPhone       String?\n  buyerNtn            String?\n  buyerCnic           String?\n  tableId             String?\n  table               Table?             @relation(fields: [tableId], references: [id])\n  staffId             String?\n  staff               User?              @relation(fields: [staffId], references: [id], onDelete: SetNull)\n  subtotal            Decimal            @db.Decimal(10, 2)\n  tax                 Decimal            @db.Decimal(10, 2)\n  tip                 Decimal?           @db.Decimal(10, 2)\n  discount            Decimal?           @db.Decimal(10, 2)\n  total               Decimal            @db.Decimal(10, 2)\n  /// Nullable: held orders accumulate items + go to the kitchen long\n  /// before the operator collects payment. `payment` and `paidAt` are\n  /// both set in the same step via `payOrderAction`.\n  payment             PaymentMethod?\n  paidAt              DateTime?\n  notes               String?\n  /// BRA-issued fiscal invoice number. Populated after successful\n  /// submission to the BRA Software Fiscal Device (local or cloud).\n  fiscalInvoiceNumber String?\n  fiscalSubmittedAt   DateTime?\n  fiscalAttempts      Int                @default(0)\n  fiscalLastError     String?\n  fiscalSubmissions   FiscalSubmission[]\n  items               OrderItem[]\n  tickets             KitchenTicket[]\n  createdAt           DateTime           @default(now())\n  updatedAt           DateTime           @updatedAt\n\n  @@index([status])\n  @@index([createdAt])\n}\n\nmodel OrderItem {\n  id         String   @id @default(cuid())\n  orderId    String\n  order      Order    @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  menuItemId String\n  menuItem   MenuItem @relation(fields: [menuItemId], references: [id])\n  /// Denormalized at the time of sale so historical orders stay legible\n  /// even if the underlying menu item is renamed or deleted.\n  name       String\n  quantity   Int\n  unitPrice  Decimal  @db.Decimal(10, 2)\n  modifiers  Json?\n  note       String?\n\n  @@index([orderId])\n}\n\nenum TicketStatus {\n  pending\n  preparing\n  ready\n  served\n  /// Set when the parent order is cancelled before payment. The\n  /// kitchen surface keeps cancelled tickets visible (struck-out)\n  /// until a cook explicitly dismisses them so prep can be stopped\n  /// without surprises.\n  cancelled\n}\n\nmodel KitchenTicket {\n  id        String         @id @default(cuid())\n  orderId   String\n  order     Order          @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  stationId String\n  station   KitchenStation @relation(fields: [stationId], references: [id])\n  status    TicketStatus   @default(pending)\n  createdAt DateTime       @default(now())\n  updatedAt DateTime       @updatedAt\n\n  @@unique([orderId, stationId])\n  @@index([stationId, status])\n}\n\n// ──────────────────────────────────────────────────────────────\n// BRA fiscal device integration\n// ──────────────────────────────────────────────────────────────\n\nenum FiscalMode {\n  disabled\n  local\n  cloud\n}\n\nenum FiscalEnvironment {\n  sandbox\n  production\n}\n\n/// Workspace-wide configuration for invoice fiscalization with the\n/// Balochistan Revenue Authority (BRA). A single row is enough — we\n/// use a fixed primary key (\"default\") and upsert it on save.\n///\n/// `bearerToken` and `accessCode` are sensitive; never expose either\n/// in client-bound payloads (the query helper strips them).\nmodel FiscalConfig {\n  id             String            @id @default(\"default\")\n  enabled        Boolean           @default(false)\n  mode           FiscalMode        @default(disabled)\n  environment    FiscalEnvironment @default(sandbox)\n  /// BRA-issued POS Registration Number (called POSID in the spec).\n  posId          String?\n  /// Access code paired with the POS ID; used for the local fiscal device.\n  accessCode     String?\n  /// Bearer token for the cloud endpoint (sandbox/production).\n  bearerToken    String?\n  /// Override for the local device URL. Default is the spec's `http://localhost:8524`.\n  localBaseUrl   String            @default(\"http://localhost:8524\")\n  /// PCT (Pakistan Customs Tariff) code applied to any menu item\n  /// that doesn't carry its own. BRA's documented placeholder is \"00000000\".\n  defaultPctCode String            @default(\"00000000\")\n  /// Optional display-only metadata (helps operators sanity-check the config).\n  businessName   String?\n  bntn           String?\n  /// Auto-submit invoices to BRA when a POS order is placed.\n  /// When false, operators submit manually from the order detail drawer.\n  autoSubmit     Boolean           @default(true)\n  updatedAt      DateTime          @updatedAt\n}\n\n/// One row per submission attempt against the BRA fiscal device.\n/// Keeps a forensic audit so failed submissions can be re-driven and\n/// successful ones can be reconciled with BRA's portal later.\nmodel FiscalSubmission {\n  id                  String            @id @default(cuid())\n  orderId             String\n  order               Order             @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  mode                FiscalMode\n  environment         FiscalEnvironment\n  endpoint            String\n  /// Whether BRA accepted the invoice (Code == \"100\" in the spec).\n  succeeded           Boolean\n  /// Fiscal invoice number returned by BRA on success.\n  fiscalInvoiceNumber String?\n  /// Raw response code / message from BRA.\n  responseCode        String?\n  responseMessage     String?\n  errorMessage        String?\n  /// Payload + response captured verbatim for debugging.\n  requestBody         Json\n  responseBody        Json?\n  attemptedAt         DateTime          @default(now())\n\n  @@index([orderId])\n  @@index([attemptedAt])\n}\n\n// ──────────────────────────────────────────────────────────────\n// Activity audit log (recent events feed)\n// ──────────────────────────────────────────────────────────────\n\nenum ActivityType {\n  order\n  stock\n  staff\n  system\n}\n\nenum ShiftStatus {\n  scheduled\n  confirmed\n  completed\n  missed\n}\n\n/// A scheduled work block for one team member on one calendar day.\n/// `start`/`end` are stored as ISO timestamps (in UTC) so we can do\n/// time-based queries; the UI does the day-of-week + local-time\n/// formatting.\nmodel Shift {\n  id        String      @id @default(cuid())\n  userId    String\n  user      User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  date      DateTime    @db.Date\n  start     DateTime\n  end       DateTime\n  status    ShiftStatus @default(scheduled)\n  notes     String?\n  createdAt DateTime    @default(now())\n  updatedAt DateTime    @updatedAt\n\n  @@index([userId])\n  @@index([date])\n}\n\nenum AttendanceState {\n  onTime\n  late\n  absent\n}\n\n/// One row per (user, day) recording how they showed up. The\n/// dashboard rolls these up into the 7-day attendance chart.\nmodel Attendance {\n  id          String          @id @default(cuid())\n  userId      String\n  user        User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  date        DateTime        @db.Date\n  state       AttendanceState\n  minutesLate Int?\n  createdAt   DateTime        @default(now())\n\n  @@unique([userId, date])\n  @@index([date])\n}\n\n/// Append-only feed of operationally interesting events — order\n/// placed/paid/cancelled, stock received, members invited, etc.\n/// Powers the dashboard's \"Recent activity\" panel and lets us\n/// reconstruct an at-a-glance timeline without trawling individual\n/// tables.\nmodel Activity {\n  id          String       @id @default(cuid())\n  type        ActivityType\n  title       String\n  description String?\n  /// Optional human-readable actor (cashier name) captured at write\n  /// time so deleting a user later doesn't blank the audit log.\n  actorName   String?\n  actorId     String?\n  /// Loose backrefs so we can deep-link or join when we need to.\n  orderId     String?\n  metadata    Json?\n  createdAt   DateTime     @default(now())\n\n  @@index([createdAt])\n  @@index([type])\n}\n"
}

